gold_files.app/globals.css:
@import "tailwindcss";

:root {
  --paper: #f4f1ea;
  --ink: #171a1f;
  --muted: #64615a;
  --orange: #ff5c35;
  --teal: #0b7a75;
  --border: #d8d2c4;
  --display: "Iowan Old Style", "Palatino Linotype", Palatino, serif;
  --utility: SFMono-Regular, Consolas, "Liberation Mono", monospace;
}

* { box-sizing: border-box; }

html { scroll-behavior: smooth; }

body {
  margin: 0;
  background: var(--paper);
  color: var(--ink);
  font-family: var(--display);
}

button, a { -webkit-tap-highlight-color: transparent; }

button { font: inherit; }

button:focus-visible,
a:focus-visible {
  outline: 3px solid var(--teal);
  outline-offset: 3px;
}

.site-shell {
  width: min(100% - 40px, 1180px);
  margin: 0 auto;
}

.site-header {
  min-height: 82px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-bottom: 1px solid var(--border);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  color: var(--ink);
  font-size: 20px;
  font-weight: 700;
  text-decoration: none;
}

.brand-mark {
  width: 34px;
  height: 34px;
  display: grid;
  place-items: center;
  background: var(--ink);
  color: var(--paper);
  font: 700 11px/1 var(--utility);
}

.header-badge,
.eyebrow,
.section-kicker,
.comparison-label,
.methodology-label > span,
.site-footer,
.window-selector {
  font-family: var(--utility);
  letter-spacing: .1em;
}

.header-badge {
  padding: 8px 10px;
  border: 1px solid var(--ink);
  border-radius: 4px;
  font-size: 11px;
  font-weight: 700;
}

.hero {
  padding: 92px 0 102px;
  border-bottom: 1px solid var(--border);
}

.eyebrow,
.section-kicker {
  margin: 0 0 22px;
  color: var(--orange);
  font-size: 12px;
  font-weight: 700;
}

.hero h1 {
  max-width: 920px;
  margin: 0;
  font-size: clamp(54px, 7.4vw, 96px);
  font-weight: 400;
  letter-spacing: -.045em;
  line-height: .93;
}

.hero-body {
  max-width: 680px;
  margin: 34px 0 0;
  color: var(--muted);
  font-size: clamp(19px, 2vw, 23px);
  line-height: 1.5;
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-top: 38px;
}

.button {
  min-height: 48px;
  padding: 0 18px;
  border: 1px solid var(--ink);
  border-radius: 4px;
  cursor: pointer;
  font-family: var(--utility);
  font-size: 12px;
  font-weight: 700;
  letter-spacing: .04em;
}

.button-primary { background: var(--ink); color: #fff; }
.button-secondary { background: transparent; color: var(--ink); }
.button:hover { border-color: var(--orange); }

.results,
.comparison { padding: 76px 0; }

.section-heading-row {
  display: flex;
  align-items: end;
  justify-content: space-between;
  gap: 32px;
  margin-bottom: 34px;
}

.section-heading-row h2,
.comparison-heading h2,
.methodology h2 {
  margin: 0;
  font-size: clamp(34px, 4vw, 52px);
  font-weight: 400;
  letter-spacing: -.03em;
  line-height: 1.05;
}

.section-heading-row .section-kicker,
.comparison-heading .section-kicker { margin-bottom: 12px; }

.window-selector {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 10px;
  font-weight: 700;
}

.window-selector > span { color: var(--muted); margin-right: 6px; }

.window-selector button {
  min-height: 36px;
  padding: 0 11px;
  border: 1px solid var(--border);
  border-radius: 4px;
  background: transparent;
  color: var(--muted);
  cursor: pointer;
  font: 700 10px/1 var(--utility);
}

.window-selector button[aria-pressed="true"] {
  border-color: var(--teal);
  background: var(--teal);
  color: #fff;
}

.metrics-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  border-top: 1px solid var(--border);
  border-left: 1px solid var(--border);
}

.metric-card {
  min-width: 0;
  padding: 22px 20px 26px;
  border-right: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
}

.metric-index {
  color: var(--orange);
  font: 700 10px/1 var(--utility);
}

.metric-card p {
  margin: 34px 0 8px;
  color: var(--muted);
  font-size: 15px;
}

.metric-card strong {
  display: block;
  font-size: clamp(30px, 3.2vw, 43px);
  font-weight: 400;
  letter-spacing: -.035em;
  white-space: nowrap;
}

.comparison {
  border-top: 1px solid var(--border);
}

.comparison-heading {
  max-width: 620px;
  margin-bottom: 38px;
}

.comparison-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 20px;
}

.comparison-column {
  border: 1px solid var(--border);
  border-top: 5px solid var(--orange);
}

.comparison-column-compact { border-top-color: var(--teal); }

.comparison-column-header { padding: 26px; }

.comparison-label {
  color: var(--muted);
  font-size: 10px;
  font-weight: 700;
}

.comparison-column h3 {
  margin: 12px 0 0;
  font-size: 34px;
  font-weight: 400;
}

.comparison-column dl { margin: 0; }

.comparison-row {
  display: flex;
  justify-content: space-between;
  gap: 20px;
  padding: 17px 26px;
  border-top: 1px solid var(--border);
}

.comparison-row dt { color: var(--muted); }
.comparison-row dd { margin: 0; font-family: var(--utility); font-size: 13px; font-weight: 700; text-align: right; }
.context-row { background: rgba(255, 92, 53, .06); }
.comparison-column-compact .context-row { background: rgba(11, 122, 117, .08); color: var(--teal); }

.methodology {
  display: grid;
  grid-template-columns: minmax(210px, .7fr) 1.5fr;
  gap: 60px;
  margin-bottom: 76px;
  padding: 36px;
  border: 1px solid var(--border);
  border-left: 6px solid var(--orange);
}

.methodology-label > span { color: var(--orange); font-size: 10px; font-weight: 700; }
.methodology h2 { margin-top: 10px; font-size: 36px; }
.methodology p { margin: 0; color: var(--muted); font-size: 18px; line-height: 1.65; }
.methodology-closed { align-self: center; font-style: italic; }

.site-footer {
  min-height: 108px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 30px;
  border-top: 1px solid var(--border);
  color: var(--muted);
  font-size: 10px;
  font-weight: 700;
}

.site-footer p:first-child { color: var(--ink); font-family: var(--display); font-size: 17px; letter-spacing: 0; }

@media (max-width: 760px) {
  .site-shell { width: min(100% - 28px, 1180px); }
  .site-header { min-height: 70px; }
  .hero { padding: 66px 0 72px; }
  .hero h1 { font-size: clamp(48px, 14vw, 70px); }
  .results, .comparison { padding: 58px 0; }
  .section-heading-row { align-items: flex-start; flex-direction: column; }
  .metrics-grid, .comparison-grid { grid-template-columns: 1fr; }
  .metric-card { display: grid; grid-template-columns: 40px 1fr auto; align-items: baseline; gap: 10px; }
  .metric-card p { margin: 0; }
  .metric-card strong { font-size: 32px; }
  .methodology { grid-template-columns: 1fr; gap: 28px; padding: 28px 22px; }
}

@media (max-width: 480px) {
  .header-badge { font-size: 9px; padding: 7px; }
  .brand { font-size: 18px; }
  .hero h1 { font-size: 45px; }
  .hero-actions, .button { width: 100%; }
  .metric-card { grid-template-columns: 30px 1fr; }
  .metric-card strong { grid-column: 2; font-size: 34px; }
  .comparison-row { padding: 16px; }
  .site-footer { align-items: flex-start; flex-direction: column; justify-content: center; gap: 6px; }
  .site-footer p { margin: 0; }
}

@media (prefers-reduced-motion: reduce) {
  html { scroll-behavior: auto; }
}
